SELECT p.name, p.age
FROM passengers p
WHERE p.embarked = 'S' AND p.survived = 1;

SELECT age_group, AVG(survival_rate_by_age) AS average_survival_rate
FROM survivor_stats
GROUP BY age_group;

SELECT l.boat_number
FROM lifeboats l
WHERE (l.occupied / l.capacity) > (SELECT AVG(occupied / capacity) FROM lifeboats);
